    "Random", H4_r2_1$R2_conditional - H4_r2_1$R2_marginal,
    "Interaction", H4_r2_1$R2_marginal - H4_r2_interaction$R2_marginal,
  ) |> 
  mutate(r2= r2 |> round(2))
